-- ============================================================================
-- MonBonAgent — Phase 6 : Seed des villes de France (top 120 + régions)
-- ============================================================================
-- Source : INSEE populations municipales 2024 — approximations arrondies.
-- Idempotent via ON CONFLICT (slug) — safe à relancer.
-- ============================================================================

on conflict (slug) do update set
  name = excluded.name,
  department = excluded.department,
  postal_code = excluded.postal_code,
  region = excluded.region,
  lat = excluded.lat,
  lng = excluded.lng,
  population = excluded.population,
  updated_at = now();
